let isLocal = global.get('localNetwork') || false;

msg.payload = {
    ip: msg.req.ip,
    localNetwork: isLocal
};
return msg;

let success = msg.payload.includes('TTL=');
let localNetwork = global.get('localNetwork') || false;
let failCount = global.get('failCount') || 0;

if (!localNetwork) {
    // Logic A: not granted — one success is enough to grant
    if (success) {
        global.set('localNetwork', true);
        global.set('failCount', 0);
    }
} else {
    // Logic B: granted — require 3 consecutive failures to revoke
    if (!success) {
        failCount++;
        if (failCount >= 3) {
            global.set('localNetwork', false);
            global.set('failCount', 0);
        } else {
            global.set('failCount', failCount);
        }
    } else {
        global.set('failCount', 0); // reset on success
    }
}

msg.payload = 'Local network: ' + global.get('localNetwork') + ' (failCount: ' + failCount + ')';
return msg;

let socketId = msg._client.socketId;
let socketIp = msg._client.socketIp;
let isLocal = global.get('localNetwork') || false;

// Only act on connect and change events
if (msg.payload !== 'connect' && msg.payload !== 'change') return null;

let ipOk = (
    socketIp === '127.0.0.1' ||
    socketIp.startsWith('192.168.')
);

let blocked = !(ipOk && isLocal);

msg.payload = {
    _client: { socketId: socketId },
    groups: blocked
        ? { disable: ["59b84ef62cd6fe8a"] }
        : { enable: ["59b84ef62cd6fe8a"] }
};

return msg;

// OFFLINE case
if (msg.topic === "__offline__" || msg.topic === "offline") {
    let offline = {
        text: "OFFLINE",
        style: "color:red",
        code: "0"
    };
    flow.set("lastStatus", offline);
    flow.set("floatingSinceState", "none");
    flow.set("floatingSinceTime", null);
    global.set("esp32Online", false);

    msg.payload = `<div style="${offline.style}">${offline.text}</div>`;
    let msg2 = { payload: "" };
    return [msg, msg2];
}

// FLASH case
if (msg.topic === "flashTrigger") {
    let st = flow.get("lastStatus");
    if (!st) return [null, null];

    if (msg.payload === "__flash__") {
        // dot ON
        msg.payload = `<div><span style="color:lime;">●</span> <span style="${st.style}">${st.text}</span></div>`;
    } else {
        // dot OFF
        msg.payload = `<div style="${st.style}">${st.text}</div>`;
    }
    return [msg, null];
}

// Ignore everything except real status messages
if (msg.topic !== "globe/status") {
    return [null, null];
}

// NORMAL STATUS case
let code = ("" + msg.payload).trim();

let statusMap = {
    "0": { text: "wait for globe position sync", style: "color:yellow;" },
    "1": { text: "free running", style: "color:yellow;" },
    "2": { text: "measuring rotation speed", style: "color:yellow" },
    "3": { text: "rotation not locked to clock", style: "color:yellow" },
    "4": { text: "rotation locked to clock", style: "color:#40ff40" },
    "5": { text: "rotation is OFF", style: "color:#40ff40;" },
    "6": { text: "globe is not floating", style: "color:yellow;font-weight:bold;" },
    "17": { text: "Error: dropped globe", style: "color:red;font-weight:bold;background:#ffcccc;" },
    "18": { text: "Error: sticky globe", style: "color:red;font-weight:bold;background:#ffcccc;" },
    "19": { text: "Error: overload", style: "color:red;font-weight:bold;background:#ffcccc;" },
    "20": { text: "Error: temp too high", style: "color:red;font-weight:bold;background:#ffcccc;" },
    "99": { text: "OFFLINE", style: "color:red;" }                // last will
};

let mapped = statusMap[code];

// safety only (should never occur)
if (!mapped) {
    mapped = { text: "OFFLINE", style: "color:red", code: "0" };
}

mapped.code = code;
flow.set("lastStatus", mapped);

if (code === "99") {
    global.set("esp32Online", false);
} else {
    global.set("esp32Online", true);
}

msg.payload = `<div style="${mapped.style || ""}">${mapped.text}</div>`;
return [msg, null];

let data = msg.payload;

let actRotTimeMsg = { payload: data.actRotTime} ;
let rotSyncErrorMsg = { payload: data.rotSyncError};
let greenwichLagMsg = { payload: data.greenwichLag};

// Return all three
return [actRotTimeMsg, rotSyncErrorMsg, greenwichLagMsg];

if (msg.topic === "globe/heartbeat/set") {
    return null;
}

flow.set("lastSeen", Date.now());
flow.set("flash", true);
return null;

let last = flow.get("lastSeen");
if (!last) return null;

last = new Date(last);
let current = new Date();

let diffSeconds = Math.floor((current.getTime() - last.getTime()) / 1000);

// Build the base text
let text;

if (diffSeconds < 60) {
    text = diffSeconds + " seconds ago";
} else {
    let sameDay =
        current.getFullYear() === last.getFullYear() &&
        current.getMonth() === last.getMonth() &&
        current.getDate() === last.getDate();

    if (sameDay) {
        text = last.toLocaleTimeString();
    } else {
        let months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
        let hh = String(last.getHours()).padStart(2, "0");
        let mm = String(last.getMinutes()).padStart(2, "0");
        let ss = String(last.getSeconds()).padStart(2, "0");
        text = months[last.getMonth()] + " " + last.getDate() + ", " + last.getFullYear() + " " + hh + ":" + mm;
    }
}


// Check if a flash is requested
let flash = flow.get("flash");

if (flash) {
    // Flash ON (brief highlight)
    msg.payload = "<span style='color:lime;font-weight:bold;'>" + text + "</span>";

    // Clear flash flag immediately
    flow.set("flash", false);

    // Schedule a reset after 200 ms
    setTimeout(() => {
        node.send({ payload: text });
    }, 100);

    return msg;
}

// Normal display
msg.payload = text;
return msg;

flow.set("statusFlash", true);

// Flash ON
node.send({ topic: "flashTrigger", payload: "__flash__" });

// Flash OFF after 300 ms
setTimeout(() => {
    node.send({ topic: "flashTrigger", payload: "__noflash__" });
}, 300);

return null;

let last = flow.get("lastSeen") || 0;
let now = Date.now();

// 10 seconds without heartbeat = offline
if (now - last > 3000) {
    msg.topic = "__offline__";
    msg.payload = "";
    return msg;
}

return null;

setTimeout(() => node.send({ topic: "globe/settings/request", payload: "" }), 0);
setTimeout(() => node.send({ topic: "globe/PIDsettings/request", payload: "" }), 2000);
setTimeout(() => node.send({ topic: "globe/vertPosSetpoint/request", payload: "" }), 400);
setTimeout(() => node.send({ topic: "globe/coilPhaseAdjust/request", payload: "" }), 6000);
return null;

const topic = msg.topic;
const state = flow.get("floatingSinceState") || "none";

if (topic === "globe/status") {
    let code = parseInt(("" + msg.payload).trim());
    let newState;
    if (code >= 0 && code <= 5) newState = "floating";
    else                        newState = "none";

    if (newState !== state) {
        flow.set("floatingSinceState", newState);
        flow.set("floatingSinceTime", null);
    }

    if (newState === "floating") {
        if (!flow.get("floatingSinceTime")) {
            msg.payload = "<span style='color:#AAAAAA;'>floating since just now</span>";
            return msg;
        }
        return null;
    }

    msg.payload = "";
    return msg;
}

if (topic === "node-red/secondsFloating") {
    if (state !== "floating") {
        msg.payload = "";
        return msg;
    }

    let secs = parseInt(("" + msg.payload).trim());
    if (isNaN(secs)) return null;

    let startMs = Date.now() - (secs * 1000);
    let start = new Date(startMs);
    start.setSeconds(0, 0);

    flow.set("floatingSinceTime", startMs);

    let now = new Date();

    let hh = String(start.getHours()).padStart(2, "0");
    let mm = String(start.getMinutes()).padStart(2, "0");

    let timeStr;

    let months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    timeStr = months[start.getMonth()] + " " + start.getDate() + ", " + start.getFullYear() + " " + hh + ":" + mm;    

    msg.payload = "<span style='color:#AAAAAA;'>floating since " + timeStr + "</span>";
    return msg;
}

return null;

let data = msg.payload;

let secondsFloating = { payload: data.secondsFloating, topic: "node-red/secondsFloating"};

let missedAndMaxPending = data.eventsMissed + " (" + data.maxEventsPending + ")";
let eventsMissedAndMaxPending = { payload: missedAndMaxPending};
let maxEventQueueBytesUsed = {payload: data.maxEventQueueBytesUsed};

return [secondsFloating, eventsMissedAndMaxPending, maxEventQueueBytesUsed];

let obj = msg.payload;

if (typeof obj !== "object" || obj === null) {
    return [msg, null];
}

let msg1 = { topic: msg.topic, payload: "" + obj.s };
let msg2 = { payload: obj.f };
return [msg1, msg2];

let obj = msg.payload || 0;
let ringing = (obj & 0x01) !== 0;
let alarmActive = ((obj & 0x02) !== 0) && !ringing;

flow.set("ringActive", ringing);
flow.set("alarmActive", alarmActive);

let ringMsg, alarmMsg;

if (ringing) {
    ringMsg = { ui_update: { label: "stop ring", buttonColor: "#c62828", textColor: "#ffffff" } };
    alarmMsg = { ui_update: { label: "alarm", buttonColor: "#9e9e9e", textColor: "#616161" } };
} else if (alarmActive) {
    ringMsg = { ui_update: { label: "Ring ring", buttonColor: "#9e9e9e", textColor: "#616161" } };
    alarmMsg = { ui_update: { label: "reset alarm", buttonColor: "#c62828", textColor: "#ffffff" } };
} else {
    ringMsg = { ui_update: { label: "Ring ring", buttonColor: "", textColor: "" } };
    alarmMsg = { ui_update: { label: "alarm", buttonColor: "", textColor: "" } };
}

return [ringMsg, alarmMsg];

if (!flow.get("esp32Online")) {
    flow.set("ringActive", false);
    flow.set("alarmActive", false);

    let ringMsg = { ui_update: { label: "Ring ring", buttonColor: "#9e9e9e", textColor: "#616161" } };
    let alarmMsg = { ui_update: { label: "alarm", buttonColor: "#9e9e9e", textColor: "#616161" } };
    return [ringMsg, alarmMsg];
}

return [null, null];

let ringActive = flow.get("ringActive");
let alarmActive = flow.get("alarmActive");

if (msg.payload === "start ring") {
    if (ringActive) {
        msg.payload = "stop ring";
    }
} else if (msg.payload === "start alarm") {
    if (alarmActive) {
        msg.payload = "stop ring";
    }
}

return msg;

let data = msg.payload;

let setRotTimeMsg = { payload: data.setRotTime } ;
let setLedEffectMsg = { payload: data.setLedEffect};
let setLedEffectSpeedMsg = { payload: data.setLedEffectSpeed};

// Return all three
return [setRotTimeMsg, setLedEffectMsg, setLedEffectSpeedMsg];

const gain_center = 0.7;
const gain_incr = 0.0125;

const dif_center = 23;
const dif_incr = 0.125;

const int_center = 10;
const int_incr = 0.5;

const center_index = 16;        // range: 0-32

let data = msg.payload;

let setGainAdjustMsg = {
    payload: gain_center + (data.setGainAdjust - center_index) * gain_incr
};

let setDifTimeAdjustMsg = {
    payload: dif_center + (data.setDifTimeAdjust - center_index) * dif_incr
};

let setIntTimeAdjustMsg = {
    payload: int_center + (data.setIntTimeAdjust - center_index) * int_incr
};

// Return all three outputs 
return [setGainAdjustMsg, setDifTimeAdjustMsg, setIntTimeAdjustMsg];

let rot   = flow.get("setRotTime");
let eff   = flow.get("setLedEffect");
let speed = flow.get("setLedEffectSpeed");

msg.payload = {
    setRotTime: Number(rot),
    setLedEffect: Number(eff),
    setLedEffectSpeed: Number(speed)
};

return msg;

// Keys used in flow context
const keys = [
    "setRotTime",
    "setLedEffect",
    "setLedEffectSpeed"
];

// Read values from context
let values = keys.map(k => {
    let v = flow.get(k);
    return (v === undefined) ? "" : v;   // preserve 0, replace only undefined
});

// Send to the three dropdowns
return [
    { payload: values[0] },
    { payload: values[1] },
    { payload: values[2] }
];

// ----- Gain parameters -----
const minVal = 0.5;         // minimim value
const incr   = 0.0125;      // step size
const minIdx = 0;           // minimum step
const maxIdx = 32;          // maximum step

// Incoming GAIN VALUE from spinner (0.5 ... 0.9)
let gain = Number(msg.payload);
let idx = Math.round((gain - minVal)/ incr);
let snappedGain = minVal + idx * incr;

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setGainAdjust", idx);
flow.set("gain_value", snappedGain);

// Output ONLY the index
return { payload: idx };

// PID differentiation time constant (mS) parameters
const minVal = 21       // minimum value
const incr   = 0.125;   // step size
const minIdx = 0;       // minimum step
const maxIdx = 32;      // maximum step

// Incoming DIFF.TIME CONST. VALUE from spinner (0.5 ... 0.9)
let difTimeConst = Number(msg.payload);

// Snap the t.c. to the nearest valid step
let snappedDifTimeConst = minVal + Math.round((difTimeConst - minVal) / incr) * incr;

// Compute index from snapped dif.time constant
let idx = Math.round((snappedDifTimeConst - minVal) / incr);

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setDifTimeAdjust", idx);
flow.set("difTime_value", snappedDifTimeConst);

// Output ONLY the index
return { payload: idx };

// PID integration time constant (second) parameters
const minVal = 2;       // minimum value 
const incr   = 0.5;     // step size
const minIdx   = 0;     // minimum step
const maxIdx   = 32;    // maximum step

// Incoming INT.TIME CONST. VALUE from spinner (0.5 ... 0.9)
let intTimeConst = Number(msg.payload);

// Snap the t.c. to the nearest valid step
let snappedIntTimeConst = minVal + Math.round((intTimeConst - minVal) / incr) * incr;

// Compute index from snapped int.time constant
let idx = Math.round((snappedIntTimeConst - minVal) / incr);

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setIntTimeAdjust", idx);
flow.set("intTime_value", snappedIntTimeConst);

// Output ONLY the index
return { payload: idx };

const keys = [
    "gain_value",
    "difTime_value",
    "intTime_value"
];

// Read values from context
let values = keys.map(k => {
    let v = flow.get(k);
    return (v === undefined) ? "" : v;   // preserve 0, replace only undefined
});

// Send to the three dropdowns
return [
    { payload: values[0] },
    { payload: values[1] },
    { payload: values[2] }
];

flow.set("setVertPosIndex", msg.payload);
flow.set("vertPosIndex_value", msg.payload);
return msg;

let vertPos = flow.get("setVertPosIndex");
let isLocal = global.get("localNetwork");

msg.payload = {
    setVertPosSetpoint: Number(vertPos),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let v = flow.get("vertPosIndex_value");
msg.payload = (v === undefined) ? "" : v;
return {payload: msg.payload};

let gain   = flow.get("setGainAdjust");
let diffTC = flow.get("setDifTimeAdjust");
let intTc  = flow.get("setIntTimeAdjust");
let isLocal = global.get("localNetwork");

msg.payload = {
    setGainAdjust: Number(gain),
    setDifTimeAdjust: Number(diffTC),
    setIntTimeAdjust: Number(intTc),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let coilPhase = flow.get("coilPhaseAdjust_value");
coilPhase = (coilPhase === undefined) ? "" : coilPhase;
if (coilPhase >= 90) { coilPhase = coilPhase - 180; }
return {payload: coilPhase*2};

let coilPhaseOut = msg.payload;                             // valid values: -180 to 178 degrees

coilPhaseOut = Math.round(coilPhaseOut /2);                 
coilPhaseOut = Math.max(-90, Math.min(89, coilPhaseOut));   // Clamp to -90 to 89 
if(coilPhaseOut < 0) {coilPhaseOut += 180;}                 // -90 to -1 => 90 to 179 

let snappedValue = coilPhaseOut;                        // Clamped to -180 to 178 degrees           

flow.set("setCoilPhaseAdjust", coilPhaseOut);
flow.set("coilPhaseAdjust_value", snappedValue);

return {payload: coilPhaseOut};

let coilPhase = flow.get("setCoilPhaseAdjust");
let isLocal = global.get("localNetwork");

msg.payload = {
    setCoilPhaseAdjust: Number(coilPhase),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let coilPhaseMessage = Number(msg.payload);
if(coilPhaseMessage >= 90) {coilPhaseMessage = coilPhaseMessage -180;}
coilPhaseMessage *=2;
return {payload: coilPhaseMessage};

let data = msg.payload;

let temp = { payload: data.heatsinkTemp} ;
let magnetDuteCycle = { payload: data.magnetDutyCycle};
let isrDuration = { payload: data.ISRduration};
let load = {payload: data.load};
let vertPosError = {payload: data.vertPosError};
let TTTintegrationTerm = {payload: data.TTTintegrTerm};

// --- last message timestamp --- 
let now = new Date(); let timeString = now.toLocaleString(); // e.g. "3/2/2026, 16:51:12" 
let timestampMsg = { payload: timeString };

return [temp, magnetDuteCycle, isrDuration, load, vertPosError, TTTintegrationTerm, timestampMsg];

if (msg.topic === "globe/wireCommQuality") {
    flow.set("lastWireQuality", parseInt(msg.payload));
}

let online = global.get("esp32Online");
let v = online ? (flow.get("lastWireQuality") || 0) : 0;

let gaugeMsg = { payload: v };
let labelMsg = { payload: v === 0 ? "No link" : (v === 100 ? "OK" : "Degraded") };

return [gaugeMsg, labelMsg];
